#include <stdio.h>
#include <stdbool.h>

#define TABLE_SIZE 100

// Structure for hash table entry
typedef struct {
    int key;
    int value;
    bool occupied;
} HashEntry;

// Simple hash function
int hash(int key) {
    return key % TABLE_SIZE;
}

// Insert with collision detection
int insert(HashEntry table[], int key, int value) {
    int collisions = 0;
    int index = hash(key);
    int original_index = index;

    // Linear probing for collision resolution
    while (table[index].occupied) {
        if (table[index].key == key) {
            // Key exists, update value
            table[index].value = value;
            return collisions;
        }
        index = (index + 1) % TABLE_SIZE;
        collisions++;

        if (index == original_index) {
            printf("Table is full!\n");
            return -1;
        }
    }

    table[index].key = key;
    table[index].value = value;
    table[index].occupied = true;

    return collisions;
}

// Pigeonhole principle checker
void check_pigeonhole_guarantee(int items, int slots) {
    if (items > slots) {
        printf("PIGEONHOLE PRINCIPLE: With %d items and %d slots,\n", items, slots);
        printf("  COLLISION IS GUARANTEED!\n");
        printf("  At least one slot will have %d items\n", 
               (items + slots - 1) / slots);
    } else {
        printf("No collision guaranteed with current load\n");
    }
}

int main() {
    HashEntry table[TABLE_SIZE] = {0};

    // Test: Insert 101 items into 100-slot table
    int num_items = 101;
    check_pigeonhole_guarantee(num_items, TABLE_SIZE);

    // Insert sample data
    for (int i = 0; i < num_items - 1; i++) {
        int collisions = insert(table, i + 100, i * 10);
    }

    printf("\nTotal items inserted: %d\n", num_items - 1);
    printf("Load factor: %.2f\n", (float)(num_items - 1) / TABLE_SIZE);

    return 0;
}
